noncompliant:
#include <cstdlib>
#include <string>

void bad_allocation() {
    // Noncompliant: using C-style allocation
    std::string* pStringArray = static_cast<std::string*>(malloc(10 * sizeof(std::string)));

    struct Person { int age; std::string name; };
    // Noncompliant: using malloc for C++ objects
    Person* p = static_cast<Person*>(malloc(sizeof(Person)));

    free(pStringArray); // Also problematic
    free(p);
}

compliant:
#include <memory>
#include <vector>
#include <string>

void good_allocation() {
    // Compliant: using C++ allocation
    std::vector<std::string> stringArray(10);

    struct Person { int age; std::string name; };
    // Compliant: using smart pointers
    auto p = std::make_unique<Person>();

    // Or using new/delete if needed
    Person* p2 = new Person();
    delete p2;
}
